+function normalizePendingRunIds(runIds: Iterable<string>): string[] {
+  const seen = new Set<string>();
+  for (const runId of runIds) {
+    const normalized = runId.trim();
+    if (!normalized || seen.has(normalized)) {
+      continue;
+    }
+    seen.add(normalized);
+  }
+  return [...seen];
+}
